<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        :root {
            --primary: #2563eb;
            --danger: #dc2626;
            --bg: #f8fafc;
            --card: #ffffff;
            --text: #1e293b;
        }

        body {
            font-family: system-ui, -apple-system, sans-serif;
            background-color: var(--bg);
            color: var(--text);
            line-height: 1.5;
            margin: 0;
            padding: 20px;
        }

        .container {
            max-width: 600px;
            margin: 0 auto;
        }

        h1 { text-align: center; }

        .card {
            background: var(--card);
            padding: 20px;
            border-radius: 8px;
            box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1);
            margin-bottom: 20px;
        }

        .form-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            font-weight: 600;
            margin-bottom: 5px;
        }

        input, select, textarea {
            width: 100%;
            padding: 8px;
            border: 1px solid #cbd5e1;
            border-radius: 4px;
            box-sizing: border-box;
        }

        button {
            cursor: pointer;
            background: var(--primary);
            color: white;
            border: none;
            padding: 10px 20px;
            border-radius: 4px;
            font-weight: bold;
            width: 100%;
        }

        button:hover { opacity: 0.9; }

        #form-error {
            color: var(--danger);
            font-size: 0.875rem;
            margin-top: 10px;
            min-height: 1.2em;
        }

        .filters {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
            gap: 10px;
            align-items: end;
        }

        .summary-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 10px;
            margin-bottom: 20px;
        }

        .total-box {
            grid-column: span 2;
            font-size: 1.5rem;
            font-weight: bold;
            border-bottom: 2px solid var(--primary);
            padding-bottom: 5px;
        }

        .expense-list {
            list-style: none;
            padding: 0;
        }

        .expense {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 10px;
            border-bottom: 1px solid #e2e8f0;
        }

        .expense:last-child { border-bottom: none; }

        .exp-info { display: flex; flex-direction: column; }
        .exp-meta { font-size: 0.8rem; color: #64748b; }

        .exp-del {
            background: var(--danger);
            width: auto;
            padding: 5px 10px;
            font-size: 0.8rem;
        }

        .cat-total {
            background: #f1f5f9;
            padding: 5px;
            border-radius: 4px;
            text-align: center;
            font-size: 0.9rem;
        }
    </style>
</head>
<body>

<div class="container">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <div class="card">
        <form id="expense-form">
            <div class="form-group">
                <label for="amount">Amount</label>
                <input type="number" id="amount" step="0.01" placeholder="0.00">
            </div>
            <div class="form-group">
                <label for="category">Category</label>
                <select id="category">
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date">
            </div>
            <div class="form-group">
                <label for="note">Note (Optional)</label>
                <textarea id="note" rows="2"></textarea>
            </div>
            <button type="submit" id="add-expense">Add Expense</button>
            <div id="form-error"></div>
        </form>
    </div>

    <!-- Filters -->
    <div class="card">
        <h3>Filters</h3>
        <div class="filters">
            <div class="form-group">
                <label for="filter-category">Category</label>
                <select id="filter-category">
                    <option value="all">All Categories</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div class="form-group">
                <label for="filter-from">From</label>
                <input type="date" id="filter-from">
            </div>
            <div class="form-group">
                <label for="filter-to">To</label>
                <input type="date" id="filter-to">
            </div>
        </div>
    </div>

    <!-- Summary -->
    <div class="card">
        <h3>Summary</h3>
        <div class="summary-grid">
            <div class="total-box">Total: $<span id="total">0.00</span></div>
            <div class="cat-total" data-cat="groceries">Groceries: $<span class="val">0.00</span></div>
            <div class="cat-total" data-cat="transport">Transport: $<span class="val">0.00</span></div>
            <div class="cat-total" data-cat="bills">Bills: $<span class="val">0.00</span></div>
            <div class="cat-total" data-cat="fun">Fun: $<span class="val">0.00</span></div>
        </div>
    </div>

    <!-- List -->
    <div class="card">
        <h3>History</h3>
        <ul id="expense-list" class="expense-list"></ul>
    </div>
</div>

<script>
    // State Management
    let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

    const form = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categoryInput = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const errorDisplay = document.getElementById('form-error');

    const filterCat = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    const listContainer = document.getElementById('expense-list');
    const totalDisplay = document.getElementById('total');

    // Initialization
    function init() {
        render();

        // Listeners for filters
        [filterCat, filterFrom, filterTo].forEach(el => {
            el.addEventListener('change', render);
        });

        form.addEventListener('submit', handleAddExpense);
    }

    function handleAddExpense(e) {
        e.preventDefault();
        errorDisplay.textContent = '';

        const amount = parseFloat(amountInput.value);
        const category = categoryInput.value;
        const date = dateInput.value;
        const note = noteInput.value.trim();

        // Validation
        if (isNaN(amount) || amount <= 0) {
            errorDisplay.textContent = 'Please enter a valid positive number for the amount.';
            return;
        }
        if (!date) {
            errorDisplay.textContent = 'Please select a date.';
            return;
        }

        const newExpense = {
            id: Date.now(),
            amount,
            category,
            date,
            note
        };

        expenses.push(newExpense);
        saveAndRender();

        // Reset form
        form.reset();
        amountInput.focus();
    }

    function deleteExpense(id) {
        expenses = expenses.filter(exp => exp.id !== id);
        saveAndRender();
    }

    function saveAndRender() {
        localStorage.setItem('expenses', JSON.stringify(expenses));
        render();
    }

    function render() {
        const catFilter = filterCat.value;
        const fromDate = filterFrom.value;
        const toDate = filterTo.value;

        // Filter logic
        let filtered = expenses.filter(exp => {
            const matchesCat = (catFilter === 'all' || exp.category === catFilter);
            const matchesFrom = (!fromDate || exp.date >= fromDate);
            const matchesTo = (!toDate || exp.date <= toDate);
            return matchesCat && matchesFrom && matchesTo;
        });

        // Sort newest first (by date, then by ID for stability)
        filtered.sort((a, b) => {
            const dateA = new Date(a.date);
            const dateB = new Date(b.date);
            if (dateA - dateB !== 0) return dateB - dateA;
            return b.id - a.id;
        });

        // Render List
        listContainer.innerHTML = '';
        let runningTotal = 0;
        const catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };

        filtered.forEach(exp => {
            runningTotal += exp.amount;
            catTotals[exp.category] += exp.amount;

            const li = document.createElement('li');
            li.className = 'expense';
            li.innerHTML = `
                <div class="exp-info">
                    <strong>$${exp.amount.toFixed(2)} - ${exp.category.toUpperCase()}</strong>
                    <span class="exp-meta">${exp.date} ${exp.note ? `| ${exp.note}` : ''}</span>
                </div>
                <button class="exp-del" onclick="deleteExpense(${exp.id})">Delete</button>
            `;
            listContainer.appendChild(li);
        });

        // Update Summary UI
        totalDisplay.textContent = runningTotal.toFixed(2);

        document.querySelectorAll('.cat-total').forEach(el => {
            const cat = el.getAttribute('data-cat');
            el.querySelector('.val').textContent = catTotals[cat].toFixed(2);
        });
    }

    init();
</script>

</body>
</html>
